fullScript:
#!/bin/bash
set -euo pipefail

# Node.js Built-in Test Runner Setup

echo "==> Checking Node.js version..."
NODE_VERSION=$(node -v | cut -d'.' -f1 | tr -d 'v')
if [ "$NODE_VERSION" -lt 20 ]; then
  echo "ERROR: Node.js 20+ required for stable test runner. Current: $(node -v)"
  exit 1
fi
echo "  Node.js $(node -v) - OK"

echo "==> Creating sample module..."
cat > math.js <<'EOF'
function add(a, b) { return a + b; }
function multiply(a, b) { return a * b; }
function divide(a, b) {
  if (b === 0) throw new Error('Division by zero');
  return a / b;
}
module.exports = { add, multiply, divide };
EOF

echo "==> Creating test file..."
mkdir -p tests
cat > tests/math.test.js <<'EOF'
const { describe, it } = require('node:test');
const assert = require('node:assert/strict');
const { add, multiply, divide } = require('../math.js');

describe('add', () => {
  it('adds positive numbers', () => {
    assert.strictEqual(add(2, 3), 5);
  });
  it('adds negative numbers', () => {
    assert.strictEqual(add(-2, -3), -5);
  });
});

describe('multiply', () => {
  it('multiplies numbers', () => {
    assert.strictEqual(multiply(3, 4), 12);
  });
  it('handles zero', () => {
    assert.strictEqual(multiply(5, 0), 0);
  });
});

describe('divide', () => {
  it('divides numbers', () => {
    assert.strictEqual(divide(10, 2), 5);
  });
  it('throws on division by zero', () => {
    assert.throws(() => divide(1, 0), { message: 'Division by zero' });
  });
});
EOF

echo "==> Running tests..."
node --test

echo ""
echo "==> Running with coverage..."
node --test --experimental-test-coverage
